// Generated by make_tool. Improved by agent: cross-platform path handling.

$toolDefinition_notes_list = array (
  'type' => 'function',
  'function' => 
  array (
    'name' => 'notes_list',
    'description' => 'List all stored notes in the agent\'s workspace. Returns keys and sizes.',
    'parameters' => 
    array (
      'type' => 'object',
      'properties' => 
      (object) array(
      ),
      'required' => 
      array (
      ),
    ),
  ),
);

if (! function_exists('notes_list')) {
    function notes_list()
    {
        $notesDir = realpath(__DIR__ . '/../../workspace/notes');
        if ($notesDir === false || !is_dir($notesDir)) {
            return json_encode(['notes' => [], 'count' => 0]);
        }
        $iterator = new RecursiveIteratorIterator(
            new RecursiveDirectoryIterator($notesDir, RecursiveDirectoryIterator::SKIP_DOTS)
        );
        $notes = [];
        foreach ($iterator as $file) {
            if ($file->isFile() && $file->getExtension() === 'note') {
                $fullPath = str_replace('\\', '/', $file->getPathname());
                $notesDirNormalized = str_replace('\\', '/', $notesDir);
                $relativePath = str_replace($notesDirNormalized . '/', '', $fullPath);
                $key = str_replace('.note', '', $relativePath);
                $notes[] = [
                    'key' => $key,
                    'size' => $file->getSize(),
                    'modified' => date('Y-m-d H:i:s', $file->getMTime())
                ];
            }
        }
        return json_encode(['notes' => $notes, 'count' => count($notes)]);
    }
}
